parameters.jsonBody:
={{ JSON.stringify({
  "model": "analyze",
  "messages": [
    {
      "role": "system",
      "content": "You are a tax manager job evaluator. Score this job posting on a 0-100 scale using these factors:\n\n1. ASC 740 focus (0-25): Direct provision/tax accounting work scores highest. Explicit mention of income tax provision, deferred tax, ASC 740, tax accounting. Score 0 if none, 25 if primary focus.\n2. Team leadership (0-15): Managing staff, mentoring. Established team, manager role, team of 5+. Score 0 if solo contributor, 15 if managing a team.\n3. M&A / transaction experience (0-15): Deal-related tax, due diligence, transaction. Score 0 if none, 15 if significant.\n4. Technology fit (0-10): OneSource, Alteryx, Power BI, modern tools, automation focus, data analytics. Score 0 if none, 10 if strong tech emphasis.\n5. Location preference (0-10): Remote = 10, Houston = 8, Other TX = 6, hybrid in target metros = 5, onsite other = 3.\n6. Seniority match (0-15): Manager/Senior Manager = 15, Director = 10, Staff/Senior = 7, VP/Partner = 5.\n7. Company stability (0-10): Big4/large firms = 10, public/established = 8, mid-size = 5, startup = 2.\n\nReturn ONLY this JSON — no other text:\n{\"score\": <0-100>, \"breakdown\": {\"asc740\": <0-25>, \"team_leadership\": <0-15>, \"ma_transaction\": <0-15>, \"technology\": <0-10>, \"location\": <0-10>, \"seniority\": <0-15>, \"stability\": <0-10>}, \"strengths\": [\"...\", \"...\"], \"concerns\": [\"...\", \"...\"], \"recommendation\": \"apply\" | \"skip\" | \"maybe\", \"summary\": \"<1-2 sentence summary>\"}"
    },
    {
      "role": "user",
      "content": $json.jobText
    }
  ],
  "temperature": 0.1,
  "max_tokens": 500
}) }}

parameters.jsonOutput:
={{ (() => {
  const title = $('Prepare Job Text').item.json.title;
  const company = $('Prepare Job Text').item.json.company;
  const location = $('Prepare Job Text').item.json.location;
  const url = $('Prepare Job Text').item.json.url;
  const source = $('Prepare Job Text').item.json.source;
  const receivedAt = $('Prepare Job Text').item.json.receivedAt;

  let result;
  try {
    const content = $json.choices[0].message.content;
    result = typeof content === 'string' ? JSON.parse(content) : content;
  } catch(e) {
    result = {
      score: 0,
      breakdown: { asc740: 0, team_leadership: 0, ma_transaction: 0, technology: 0, location: 0, seniority: 0, stability: 0 },
      strengths: [],
      concerns: ['Parse error: ' + e.message],
      recommendation: 'skip',
      summary: 'Failed to parse LLM response'
    };
  }

  return JSON.stringify({
    title,
    company,
    location,
    url,
    source,
    receivedAt,
    score: result.score || 0,
    breakdown: result.breakdown || {},
    strengths: result.strengths || [],
    concerns: result.concerns || [],
    recommendation: result.recommendation || 'skip',
    summary: result.summary || ''
  });
})() }}

parameters.jsCode:
// Create Things 3 task for high-priority job via URL scheme
// Uses things:///json which is proven in Alfred things workflow

const item = $input.first().json;

const task = [
  {
    type: 'to-do',
    attributes: {
      title: `Apply: ${item.title} at ${item.company} (Score: ${item.score})`,
      notes: [
        item.summary,
        '',
        `Score: ${item.score}/100`,
        `Recommendation: ${item.recommendation}`,
        '',
        'Score Breakdown:',
        `• ASC 740: ${item.breakdown.asc740 || 0}/25`,
        `• Team Leadership: ${item.breakdown.team_leadership || 0}/15`,
        `• M&A: ${item.breakdown.ma_transaction || 0}/15`,
        `• Technology: ${item.breakdown.technology || 0}/10`,
        `• Location: ${item.breakdown.location || 0}/10`,
        `• Seniority: ${item.breakdown.seniority || 0}/15`,
        `• Stability: ${item.breakdown.stability || 0}/10`,
        '',
        `Strengths: ${(item.strengths || []).join(', ')}`,
        `Concerns: ${(item.concerns || []).join(', ')}`,
        '',
        `Link: ${item.url}`,
        `Source: ${item.source}`,
        `Received: ${item.receivedAt}`
      ].join('\n'),
      'list-id': 'Career',
      tags: ['job-search', 'high-priority', `score-${Math.floor(item.score / 10) * 10}`],
      deadline: new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      'checklist-items': [
        { type: 'checklist-item', attributes: { title: 'Review full posting' } },
        { type: 'checklist-item', attributes: { title: 'Tailor resume' } },
        { type: 'checklist-item', attributes: { title: 'Write cover letter' } },
        { type: 'checklist-item', attributes: { title: 'Submit application' } },
        { type: 'checklist-item', attributes: { title: 'Log in tracker' } }
      ]
    }
  }
];

const thingsUrl = 'things:///json?data=' + encodeURIComponent(JSON.stringify(task));

return [{
  json: {
    ...item,
    thingsUrl,
    thingsTask: task
  }
}];

